import torch
import torch.nn as nn

class ResidualBlock(nn.Module):
    def __init__(self, sublayer):
        super().__init__()
        self.sublayer = sublayer

    def forward(self, x):
        return x + self.sublayer(x)

linear = nn.Linear(2, 2)
block = ResidualBlock(linear)
x = torch.ones(2)
print("Residual output:", block(x))
